def style_ax(fig, ax):
    fig.patch.set_facecolor("#FDFAF5")
    ax.set_facecolor("#F8F4EC")
    for sp in ["top","right"]: ax.spines[sp].set_visible(False)
    ax.spines["left"].set_color(OXFORD); ax.spines["bottom"].set_color(OXFORD)
